"use client";

import { useState, useEffect } from "react";

export default function Home() {
  const [msg, setMsg] = useState("");
  const [messages, setMessages] = useState<any[]>([]);

  // 🔐 Check login
  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) {
      alert("Please login first");
      window.location.href = "/login";
    }
  }, []);

  // 🚪 Logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  // 💬 Send message
  const sendMessage = async () => {
    if (!msg) return;

    const userMessage = { role: "user", text: msg };
    setMessages((prev) => [...prev, userMessage]);

    setMsg("");

    try {
      const token = localStorage.getItem("token");

      const res = await fetch("http://127.0.0.1:8000/api/v1/chat/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`,
        },
        body: JSON.stringify({ message: userMessage.text }),
      });

      const data = await res.json();

      const aiMessage = { role: "ai", text: data.response };

      setMessages((prev) => [...prev, aiMessage]);

    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { role: "ai", text: "⚠️ Error connecting to server" },
      ]);
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🏥 Medical AI Assistant</h1>

      <button onClick={handleLogout} style={styles.logoutBtn}>
        Logout 🚪
      </button>

      <div style={styles.chatBox}>
        {messages.map((m, i) => (
          <div
            key={i}
            style={
              m.role === "user" ? styles.userMessage : styles.aiMessage
            }
          >
            {m.text}
          </div>
        ))}
      </div>

      <div style={styles.inputBox}>
        <input
          value={msg}
          onChange={(e) => setMsg(e.target.value)}
          placeholder="Enter symptoms..."
          style={styles.input}
        />

        <button onClick={sendMessage} style={styles.button}>
          Send
        </button>
      </div>
    </div>
  );
}

